#include <omp.h>
#include <cmath>
#include <vector>
#include <limits>

struct Point {
	double x, y;
};

// Function to calculate Euclidean distance between two points
double distance(Point const& p1, Point const& p2) {
	return std::sqrt(std::pow(p2.x - p1.x, 2) + std::pow(p2.y - p1.y, 2));
}

double closestPair(std::vector<Point> const& points) {
	if (points.size() < 2) return std::numeric_limits<double>::max(); // Handle edge case of less than two points

	double min_dist = std::numeric_limits<double>::max();

	// Use OpenMP to parallelize the computation
	#pragma omp parallel for shared(points, min_dist)
	for (size_t i = 0; i < points.size() - 1; ++i) {
		for (size_t j = i + 1; j < points.size(); ++j) {
			double dist = distance(points[i], points[j]);
			#pragma omp critical
			if (dist < min_dist) {
				min_dist = dist;
			}
		}
	}

	return min_dist;
}
